function binarySearch(arr, n, k) {
    let left = 0, right = n - 1;
    while (left <= right) {
        let middle = Math.floor((left + right) / 2);
        if (arr[middle] === k) {
            return middle;
        } else if (arr[middle] > k) {
            right = middle - 1;
        } else {
            left = middle + 1;
        }
    }
    return -1; // k not found
}

function main() {
    const readline = require('readline');
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    const input = [];

    rl.on('line', (line) => {
        input.push(line);
    }).on('close', () => {
        const [n, k] = input[0].split(' ').map(Number);  // First line: n and k
        const arr = input[1].split(' ').map(Number);     // Second line: array elements
        console.log(binarySearch(arr, n, k));            // Call binary search and print result
    });
}

